import type {
  MisconceptionState,
  SamMode,
  Session,
  StateTransition,
  TurnIntent,
} from "@/lib/types";

const STATE_ORDER: MisconceptionState[] = [
  "entrenched",
  "aware",
  "considering",
  "updating",
  "settled",
];

const SAM_MODES: SamMode[] = [
  "curious",
  "pushback",
  "hedging",
  "tangent",
  "fake_agreement",
  "tired",
  "asking_back",
];

function stateIndex(state: MisconceptionState): number {
  return STATE_ORDER.indexOf(state);
}

export function canTransition(from: MisconceptionState, to: MisconceptionState): boolean {
  const fromIndex = stateIndex(from);
  const toIndex = stateIndex(to);
  if (fromIndex === -1 || toIndex === -1) {
    return false;
  }

  if (fromIndex === toIndex) {
    return true;
  }

  if (toIndex === fromIndex + 1) {
    return true;
  }

  if (toIndex === fromIndex - 1) {
    return true;
  }

  return false;
}

export function isIntentForStateProgress(intent: TurnIntent | null): boolean {
  if (!intent) {
    return false;
  }
  return (
    intent.type === "express_misc" ||
    intent.type === "defend_misc" ||
    intent.type === "transfer_check"
  );
}

export function applyStateTransition(
  session: Session,
  transition: StateTransition | null | undefined,
): boolean {
  if (!transition) {
    return false;
  }

  const current = session.miscStates[transition.misc_id];
  if (!current) {
    return false;
  }

  if (current !== transition.from) {
    return false;
  }

  if (!canTransition(transition.from, transition.to)) {
    return false;
  }

  session.miscStates[transition.misc_id] = transition.to;
  return true;
}

export function pickNextMode(session: Session, random: () => number = Math.random): SamMode {
  const lastMode = [...session.turns].reverse().find((turn) => turn.role === "student")?.mode;
  const options = SAM_MODES.filter((mode) => mode !== lastMode);
  return options[Math.floor(random() * options.length)] ?? "curious";
}
